.darma-loader-darma-custom-264 {
  color: var(--loader-color, #9333ea);
  height: 30px;
  aspect-ratio: 6;
  --c: #0000 64%,currentColor 66% 98%,#0000 101%;
  background:
    radial-gradient(35% 146% at 50% 159%,var(--c)) 0 0,
    radial-gradient(35% 146% at 50% -59%,var(--c)) 25% 100%;
  background-size: calc(100%/3) 50%;
  background-repeat: repeat-x;
  clip-path: inset(0 100% 0 0);
  animation: darma-loader-darma-custom-264-l5 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-264-l5{
  50% {clip-path: inset(0)}
  to {clip-path: inset(0 0 0 100%)}
}

